select 114, c.id, m.id, s.id, 'Mensagem - Rejeição: IE do destinatário não informada', '114-mensagem-rejeicao-ie-do-destinatario-nao-informada', 'Ao ocorrer essa mensagem, é necessário que seja conferido em ''1221 - Cadastro de Terceiros'' se o mesmo possui inscrição estadual no portal Sintegra, caso não exista, confirmar se os campos no cadastro do cliente na aba ''Identificação'' campo ''Situação'' esteja ''2 - Não contribuinte', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/erros_correcoes/114/mensagem_rejeicao_ie_do_destinatario_nao_informada', '2020-07-13T18:42:00-03:00'::timestamptz, '2020-07-13T18:42:00-03:00'::timestamptz, true, now()
