select 113, c.id, m.id, s.id, 'Mensagem - Erro 2230- 70067 - Título XX - NNNNNN já Enviado ao banco!', '113-mensagem-erro-2230-70067-titulo-xx-nnnnnn-ja-enviado-ao-banco', 'Ao ocorrer esta mensagem quando for cancelar a nota fiscal na opção ''2230 - Cancelamento de Notas Fiscais'' é necessário enviar o título mencionado (Sigla + Número + Parcela) para o ''Local 000/000'' através da opção ''4214 - Envio de títulos''. São os seguintes passos: Acessar a opçã', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/erros_correcoes/113/mensagem_erro_2230_70067_titulo_xx_nnnnnn_ja_enviado_ao_banco_', '2020-07-13T17:48:00-03:00'::timestamptz, '2020-07-13T17:48:00-03:00'::timestamptz, true, now()
