select 109, c.id, m.id, s.id, 'Mensagem - Erro 12057 : Não foi possível estabelecer conexão com o servidor de revogação ou uma resposta definitiva não pôde ser obtida', '109-mensagem-erro-12057-nao-foi-possivel-estabelecer-conexao-com-o-servidor-de-revogacao-ou-uma-resposta-definitiva-nao-pode-ser-obtida', 'Esse erro costuma ocorrer quando é emitido uma Nota Fiscal de Serviços Eletrônica (NFS-e) .Para solucionar siga os passos: Acesse ''Opções do Internet Explorer - Opções da Internet - Avançadas'' e desmarque as opções: ''Verificar revogação de certificados do servidor'', ''Verificar se', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/erros_correcoes/109/mensagem_erro_12057_nao_foi_possivel_estabelecer_conexao_com_o_servidor_de_revogacao_ou_uma_resposta_definitiva_nao_pode_ser_obtida', '2020-07-03T12:10:00-03:00'::timestamptz, '2020-07-03T12:10:00-03:00'::timestamptz, true, now()
