select 108, c.id, m.id, s.id, 'Rejeição : NFC-e não pode referenciar documento fiscal', '108-rejeicao-nfc-e-nao-pode-referenciar-documento-fiscal', 'Ao tentar referenciar a Nota Fiscal de Consumidor Eletrônica (NFC-e modelo 65) através da opção ''2131 - Cadastro de Pedidos'' Aba ''Notas Referenciadas'' e ocorrer a rejeição informada é porque não é permitido o acobertamento do documento, pois, o modelo (65) já tem uma estrutura si', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/erros_correcoes/108/rejeicao_nfc_e_nao_pode_referenciar_documento_fiscal', '2020-07-03T11:27:00-03:00'::timestamptz, '2020-07-03T11:27:00-03:00'::timestamptz, true, now()
