select 107, c.id, m.id, s.id, 'Nota Fiscal de Devolução de Compra de Mercadorias a Fornecedor - Saída', '107-nota-fiscal-de-devolucao-de-compra-de-mercadorias-a-fornecedor-saida', '2113 - Cadastro de Transações - No cadastro da transação deve-se indicar a ''Característica'', o ''Tipo de Venda'' e o ''CFOP'' adequado para a operação. Utilizar ''Característica - 11 - Devolução, Remessas Troca/Garantia'' e ''Tipo Venda - CD - Devolução de Compras''. No grupo ''Destaque d', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/guia/107/nota_fiscal_de_devolucao_de_compra_de_mercadorias_a_fornecedor_saida', '2020-05-28T14:33:00-03:00'::timestamptz, '2020-05-28T14:33:00-03:00'::timestamptz, true, now()
