select 106, c.id, m.id, s.id, 'Nota Fiscal de Exportação Direta e Indireta', '106-nota-fiscal-de-exportacao-direta-e-indireta', 'CFOP na Nota Fiscal de ExportaçãoNo caso das exportações, o número ''7'' indica que é uma saída de mercadorias do país. Os três dígitos seguintes indicam a natureza mais específica da operação. Exemplo, ''7.101'' representa venda de produção do estabelecimento enquanto ''7.102'' indica', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/guia/106/nota_fiscal_de_exportacao_direta_e_indireta', '2020-05-28T10:19:00-03:00'::timestamptz, '2020-05-28T10:19:00-03:00'::timestamptz, true, now()
