select 105, c.id, m.id, s.id, 'Uso Aplicações\Empréstimos Sistema Hádron', '105-uso-aplicacoes-emprestimos-sistema-hadron', 'A aplicação financeira equivale a compra de um ativo ou título de uma empresa ou instituição com a intenção de conseguir uma boa remuneração em um determinado período de tempo. Entre os principais tipos de aplicações estão aquelas que possuem rendimento fixo e rendimento variável', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/guia/105/uso_aplicacoes_emprestimos_sistema_hadron', '2020-05-26T14:37:00-03:00'::timestamptz, '2020-05-26T14:37:00-03:00'::timestamptz, true, now()
