select 104, c.id, m.id, s.id, 'Importação de Lançamentos Contábeis', '104-importacao-de-lancamentos-contabeis', 'Este programa permite a integração entre módulos de outros aplicativos, a partir de registros exportados por estes, e o módulo Contabilidade do Sistema Hádron, gerando-se lançamentos contábeis mensais. Tais aplicativos podem ser a planilha MS-Excel (ou similares) ou quaisquer out', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/guia/104/importacao_de_lancamentos_contabeis', '2020-05-21T15:49:00-03:00'::timestamptz, '2020-05-21T15:49:00-03:00'::timestamptz, true, now()
