select 103, c.id, m.id, s.id, 'Uso do código CSOSN Sistema Hádron', '103-uso-do-codigo-csosn-sistema-hadron', 'O que é CSOSN?O CSOSN ou Código de Situação da Operação do Simples Nacional é uma numeração para operações de empresas optantes pelos Simples Nacional na emissão de NFe.Os códigos foram estabelecidos para fins de identificar a origem da mercadoria e o regime de tributação na oper', convert_from(decode('', 'base64'), 'utf8'), convert_from(decode('', 'base64'), 'utf8'), 'https://ajuda.procion.com/artigo/guia/103/uso_do_codigo_csosn_sistema_hadron', '2020-05-19T09:22:00-03:00'::timestamptz, '2020-05-19T09:22:00-03:00'::timestamptz, true, now()
